import { PublicActionPage } from '@domain/publicActionPage';
import { useMemo } from 'react';
import { useFormContext } from 'react-hook-form';
import { useTranslation } from 'react-i18next';
import { FormInputControl } from 'src/builder/PublicActionPage/components/FormInputControl';
import { CommunicationsConsentEmail } from './CommunicationsConsentEmail';

export type Props = {
  actionPage?: PublicActionPage;
  isPreview?: boolean;
};

export const EmailField = ({ actionPage, isPreview = false }: Props) => {
  const { watch } = useFormContext();
  const { t } = useTranslation('customFields');
  const donorProfile = isPreview ? null : watch('donorProfile');
  const expressCheckoutMethod = isPreview ? null : watch('expressCheckoutMethod');

  const {
    displayCommunicationsConsent,
    displayEmail,
    displayPhone,
    requireEmail,
    requireEmailOrPhone,
  } = actionPage?.fieldConfiguration || {};

  const isEmailRequired = useMemo(() => {
    return requireEmail && !requireEmailOrPhone;
  }, [requireEmail, requireEmailOrPhone]);

  return ((displayEmail ||
    expressCheckoutMethod ||
    requireEmail ||
    requireEmailOrPhone ||
    (!displayEmail && !displayPhone)) &&
    (!donorProfile || !donorProfile.email)) ||
    displayCommunicationsConsent ? (
    <div className="flex flex-col items-stretch gap-2">
      {(!donorProfile || !donorProfile.email) && !expressCheckoutMethod && (
        <FormInputControl
          formControlProps={{ className: '!mb-0' }}
          isRequired={isEmailRequired}
          label={t('contact.email')}
          name="email"
          type="email"
        />
      )}
      {displayCommunicationsConsent ? <CommunicationsConsentEmail /> : null}
    </div>
  ) : null;
};

